opencat.script:
var CK = ctx.CanvasKit;
var htmlCanvas = ctx.getCanvasById('slide-2-html-canvas');
var htmlTexture = htmlCanvas.getSubTree().makeShader(CK.TileMode.Clamp, CK.TileMode.Clamp);
var htmlLocalTime = Math.max(0, ctx.currentTime - 4.0);
var htmlPulse = Math.max(0, Math.min(htmlLocalTime / 1.8, 1));
var sksl = [
  'uniform shader image;',
  'uniform float t;',
  'uniform float pulse;',
  'half4 main(float2 xy) {',
  '  float2 center = float2(202.0, 152.0);',
  '  float2 delta = xy - center;',
  '  float dist = length(delta);',
  '  float wave = sin(dist * 0.055 - t * 5.0);',
  '  float ring = smoothstep(132.0, 18.0, abs(dist - 118.0 - sin(t * 1.7) * 22.0));',
  '  float glass = smoothstep(230.0, 24.0, dist);',
  '  float2 dir = dist < 1.0 ? float2(0.0, 0.0) : normalize(delta);',
  '  float2 tangent = float2(-dir.y, dir.x);',
  '  float bend = wave * 9.0 * glass + ring * 13.0 * pulse;',
  '  float2 uv = xy + dir * bend + tangent * sin(t * 2.4 + dist * 0.035) * 5.0;',
  '  half4 base = image.eval(uv);',
  '  half4 warm = image.eval(uv + tangent * (4.0 + ring * 6.0));',
  '  half4 cool = image.eval(uv - tangent * (4.0 + ring * 6.0));',
  '  half3 rgb = half3(warm.r, base.g, cool.b);',
  '  float portal = smoothstep(5.0, 0.0, abs(dist - 118.0 - sin(t * 1.7) * 22.0));',
  '  rgb = mix(rgb, half3(1.0, 0.64, 0.18), half(portal * 0.32));',
  '  float vignette = smoothstep(310.0, 120.0, dist);',
  '  return half4(rgb * half(0.72 + vignette * 0.42), max(base.a, half(0.96)));',
  '}',
].join('\n');
var effect = CK.RuntimeEffect.Make(sksl);
if (effect) {
  var shader = effect.makeShaderWithChildren([htmlLocalTime, htmlPulse], [htmlTexture]);
  var shaderPaint = new CK.Paint();
  shaderPaint.setShader(shader);
  htmlCanvas.drawRect(CK.XYWHRect(0, 0, 404, 304), shaderPaint);
} else {
  htmlCanvas.drawPicture(htmlCanvas.getSubTree(), 0, 0);
}

ctx.fromTo('canvas',
  { opacity: 0, scale: 0.985 },
  { opacity: 1, scale: 1, duration: 0.45, ease: 'power2.out' });
ctx.fromTo('rail',
  { opacity: 0, x: -24 },
  { opacity: 1, x: 0, duration: 0.45, ease: 'power2.out' });
ctx.fromTo('overlay',
  { opacity: 0, y: 10, scale: 0.94 },
  { opacity: 1, y: 0, scale: 1, duration: 0.35, delay: 0.18, ease: 'power2.out' });

ctx.fromTo('slide-1',
  { opacity: 0, x: 18, scale: 0.985 },
  { opacity: 1, x: 0, scale: 1, duration: 0.42, delay: 0.28, ease: 'power2.out' });
ctx.fromTo('thumb-1-selected',
  { opacity: 0 },
  { opacity: 1, duration: 0.18, delay: 0.30, ease: 'power1.out' });

var splitChars = ctx.splitText('slide-1-title', { type: 'chars' });
var splitDirs = [[-300, -180], [0, -238], [320, -168], [-320, 72], [294, 118], [-220, 218], [0, 250], [230, 210]];
var splitColorsA = ['#22d3ee', '#d946ef', '#34d399', '#facc15', '#fb923c', '#8b5cf6'];
var splitColorsB = ['#0f172a', '#D97757', '#0891b2', '#16a34a', '#7c3aed', '#ea580c'];
ctx.fromTo(splitChars,
  {
    opacity: 0,
    x: function(i) { return splitDirs[i % splitDirs.length][0]; },
    y: function(i) { return splitDirs[i % splitDirs.length][1]; },
    scale: 0.62,
    rotate: function(i) { return i % 2 === 0 ? -24 : 24; },
    color: function(i) { return splitColorsA[i % splitColorsA.length]; }
  },
  {
    opacity: 1,
    x: 0,
    y: 0,
    scale: 1,
    rotate: 0,
    color: function(i) { return splitColorsB[i % splitColorsB.length]; },
    duration: 1.55,
    delay: 0.38,
    stagger: 0.055,
    ease: 'spring.gentle'
  });
ctx.to(splitChars,
  {
    color: function(i) { return splitColorsA[(i + 2) % splitColorsA.length]; },
    duration: 0.92,
    delay: 2.16,
    stagger: 0.035,
    yoyo: true,
    repeat: 1,
    ease: 'sine.inOut'
  });
ctx.fromTo(['slide-1-kicker', 'slide-1-accent', 'slide-1-body'],
  { opacity: 0, y: 26 },
  { opacity: 1, y: 0, duration: 0.7, delay: 0.58, stagger: 0.12, ease: 'power3.out' });
ctx.fromTo('slide-1-panel',
  { opacity: 0, x: 96, y: 20, scale: 0.88 },
  { opacity: 1, x: 0, y: 0, scale: 1, duration: 0.82, delay: 0.95, ease: 'spring.gentle' });
ctx.fromTo('slide-1-target',
  { opacity: 0, scale: 0.82, rotation: -4 },
  { opacity: 1, scale: 1, rotation: 0, duration: 0.78, delay: 1.08, ease: 'spring.gentle' });
ctx.fromTo(['slide-1-burst-a', 'slide-1-burst-b', 'slide-1-burst-c', 'slide-1-burst-d'],
  { opacity: 0, scale: 0.2 },
  { opacity: 1, scale: 1, duration: 0.7, delay: 1.18, stagger: 0.09, ease: 'spring.wobbly' });
ctx.fromTo('slide-1-ray-a',
  { opacity: 0, x: -180, y: -90, scale: 0.4, rotation: -28 },
  { opacity: 1, x: 0, y: 0, scale: 1, rotation: 0, duration: 0.75, delay: 1.34, ease: 'power3.out' });
ctx.fromTo('slide-1-ray-b',
  { opacity: 0, x: 160, y: 110, scale: 0.4, rotation: 24 },
  { opacity: 1, x: 0, y: 0, scale: 1, rotation: 0, duration: 0.75, delay: 1.42, ease: 'power3.out' });
ctx.fromTo('slide-1-ray-c',
  { opacity: 0, y: 160, scale: 0.4, rotation: -6 },
  { opacity: 1, y: 0, scale: 1, rotation: 0, duration: 0.75, delay: 1.50, ease: 'power3.out' });
ctx.fromTo('slide-1-band',
  { backgroundColor: '#f8fafc' },
  { backgroundColor: '#e0f2fe', duration: 1.2, delay: 1.64, yoyo: true, repeat: 1, ease: 'sine.inOut' });

ctx.to('slide-1',
  { opacity: 0, x: -72, duration: 0.34, delay: 3.72, ease: 'power2.in' });
ctx.to('thumb-1-selected',
  { opacity: 0, duration: 0.16, delay: 3.78, ease: 'power1.in' });
ctx.fromTo('slide-2',
  { opacity: 0, x: 86, scale: 0.985 },
  { opacity: 1, x: 0, scale: 1, duration: 0.44, delay: 4.00, ease: 'power2.out' });
ctx.fromTo('thumb-2-selected',
  { opacity: 0 },
  { opacity: 1, duration: 0.18, delay: 4.08, ease: 'power1.out' });
ctx.to('count-1',
  { opacity: 0, duration: 0.12, delay: 3.92, ease: 'linear' });
ctx.fromTo('count-2',
  { opacity: 0 },
  { opacity: 1, duration: 0.12, delay: 4.04, ease: 'linear' });

ctx.fromTo(['slide-2-kicker', 'slide-2-title', 'slide-2-body'],
  { opacity: 0, x: -34 },
  { opacity: 1, x: 0, duration: 0.62, delay: 4.20, stagger: 0.11, ease: 'power3.out' });
ctx.fromTo('slide-2-html-canvas',
  { opacity: 0, y: 38, scale: 0.86, rotation: -3 },
  { opacity: 1, y: 0, scale: 1, rotation: 0, duration: 0.9, delay: 4.28, ease: 'spring.gentle' });
ctx.fromTo('slide-2-html-card',
  { opacity: 0, y: 26, scale: 0.94 },
  { opacity: 1, y: 0, scale: 1, duration: 0.72, delay: 4.72, ease: 'spring.gentle' });
ctx.fromTo(['slide-2-html-line-a', 'slide-2-html-line-b', 'slide-2-html-chip'],
  { opacity: 0, x: -22 },
  { opacity: 1, x: 0, duration: 0.54, delay: 5.02, stagger: 0.12, ease: 'power2.out' });
ctx.fromTo(['slide-2-dot-a', 'slide-2-dot-b', 'slide-2-dot-c'],
  { opacity: 0.25, scale: 0.6 },
  { opacity: 1, scale: 1.2, duration: 0.42, delay: 4.64, stagger: 0.08, yoyo: true, repeat: 3, ease: 'sine.inOut' });
ctx.fromTo(['slide-2-arrow-a', 'slide-2-arrow-b', 'slide-2-arrow-c', 'slide-2-caption'],
  { opacity: 0, x: -36 },
  { opacity: 1, x: 0, duration: 0.52, delay: 5.26, stagger: 0.07, ease: 'power2.out' });
ctx.to('slide-2-arrow-b',
  { rotation: -38, duration: 0.22, delay: 5.42, ease: 'power1.out' });
ctx.to('slide-2-arrow-c',
  { rotation: 38, duration: 0.22, delay: 5.42, ease: 'power1.out' });
ctx.fromTo('slide-2-band',
  { backgroundColor: '#fff7ed' },
  { backgroundColor: '#ffedd5', duration: 1.1, delay: 5.68, yoyo: true, repeat: 1, ease: 'sine.inOut' });

ctx.to('slide-2',
  { opacity: 0, x: -72, duration: 0.34, delay: 7.72, ease: 'power2.in' });
ctx.to('thumb-2-selected',
  { opacity: 0, duration: 0.16, delay: 7.78, ease: 'power1.in' });
ctx.fromTo('slide-3',
  { opacity: 0, x: 86, scale: 0.985 },
  { opacity: 1, x: 0, scale: 1, duration: 0.44, delay: 8.00, ease: 'power2.out' });
ctx.fromTo('thumb-3-selected',
  { opacity: 0 },
  { opacity: 1, duration: 0.18, delay: 8.08, ease: 'power1.out' });
ctx.to('count-2',
  { opacity: 0, duration: 0.12, delay: 7.92, ease: 'linear' });
ctx.fromTo('count-3',
  { opacity: 0 },
  { opacity: 1, duration: 0.12, delay: 8.04, ease: 'linear' });

ctx.fromTo(['slide-3-kicker', 'slide-3-title', 'slide-3-body'],
  { opacity: 0, y: 24 },
  { opacity: 1, y: 0, duration: 0.64, delay: 8.20, stagger: 0.12, ease: 'power3.out' });
ctx.fromTo('slide-3-lines',
  { opacity: 0, y: 36, scale: 0.94 },
  { opacity: 1, y: 0, scale: 1, duration: 0.76, delay: 8.36, ease: 'spring.gentle' });
ctx.fromTo(['slide-3-line-grid-a', 'slide-3-line-grid-b', 'slide-3-line-grid-c', 'slide-3-line-grid-d'],
  { opacity: 0, scale: 0.2 },
  { opacity: 1, scale: 1, duration: 0.46, delay: 8.72, stagger: 0.08, ease: 'power2.out' });
ctx.fromTo(['slide-3-row-1', 'slide-3-row-2', 'slide-3-row-3', 'slide-3-row-4', 'slide-3-row-5'],
  { opacity: 0, x: 64 },
  { opacity: 1, x: 0, duration: 0.58, delay: 8.94, stagger: 0.18, ease: 'power3.out' });
ctx.fromTo('slide-3-highlight',
  { opacity: 0, x: -120 },
  { opacity: 1, x: 0, duration: 0.62, delay: 9.34, ease: 'power2.out' });
ctx.to('slide-3-highlight',
  { y: 68, duration: 0.42, delay: 9.92, ease: 'power2.inOut' });
ctx.to('slide-3-highlight',
  { y: 136, duration: 0.42, delay: 10.36, ease: 'power2.inOut' });
ctx.to('slide-3-highlight',
  { y: 204, duration: 0.42, delay: 10.80, ease: 'power2.inOut' });
ctx.fromTo(['slide-3-rule-a', 'slide-3-rule-b', 'slide-3-rule-c'],
  { opacity: 0, x: -80, scale: 0.72 },
  { opacity: 1, x: 0, scale: 1, duration: 0.58, delay: 10.22, stagger: 0.12, ease: 'power2.out' });
